        ```typescript
        class MinHeap {
            private heap: [number, number, number][] = [];
            push(val: [number, number, number]) {
                this.heap.push(val);
                this.bubbleUp(this.heap.length - 1);
            }
            pop(): [number, number, number] | undefined {
                if (this.heap.length === 0) return undefined;
                const top = this.heap[0];
                const last = this.heap.pop()!;
                if (this.heap.length > 0) {
                    this.heap[0] = last;
                    this.bubbleDown(0);
                }
                return top;
            }
            private bubbleUp(idx: number) {
                while (idx > 0) {
                    let parent = Math.floor((idx - 1) / 2);
                    if (this.heap[idx][0] < this.heap[parent][0]) {
                        [this.heap[idx], this.heap[parent]]] = [this.heap[parent], this.heap[idx]]];
                        idx = parent;
                    } else break;
                }
            }
            private bubbleDown(idx: number) {
                while (true) {
                    let left = 2 * idx + 1;
                    let right = 2 * idx + 2;
                    let smallest = idx;
                    if (left < this.heap.length && this.heap[left][0] < this.heap[smallest][0]]) smallest = left;
                    if (right < this.heap.length && this.heap[right][0] < this.heap[smallest][0]])) smallest = right;
                    if (smallest !== idx) {
                        [this.heap[idx], this.heap[smallest]]] = [this.heap[smallest], this.heap[idx]]];
                        idx = smallest;
                    } else break;
                }
            }
            isEmpty(): boolean { return this.heap.length === 0; }
        }
